    test("/* @__PURE__ */ new Foo()", "");
    test("/* @__PURE__ */ new Foo(a)", "a");
    test("true && /* @__PURE__ */ noEffect()", "");
    test("false || /* @__PURE__ */ noEffect()", "");

    test("var foo = () => 1; foo(), foo()", "var foo = () => 1");
