#![expect(clippy::print_stdout)]
//! # Complete Compiler Example
//!
//! This example demonstrates the complete Oxc compilation pipeline including
//! parsing, semantic analysis, transformation, and code generation.
//!
//! ## Usage
//!
//! Create a `test.js` file and run:
//! ```bash
//! cargo run -p oxc --example compiler --features="full" [filename]
//! ```

use std::{env, io, path::Path};

use oxc::{Compiler, span::SourceType};

// Instruction:
// 1. create a `test.js`
// 2. run either
//   * `cargo run -p oxc --example compiler --features="full"`
//   * `just watch 'run -p oxc --example compiler --features="full"'`

/// Run the complete Oxc compilation pipeline on a JavaScript/TypeScript file
fn main() -> io::Result<()> {
    let name = env::args().nth(1).unwrap_or_else(|| "test.js".to_string());
    let path = Path::new(&name);
    let source_text = std::fs::read_to_string(path)?;
    let source_type = SourceType::from_path(path).unwrap();

    // Execute the full compilation pipeline
    match Compiler::default().execute(&source_text, source_type, path) {
        Ok(printed) => {
            println!("{printed}");
        }
        Err(errors) => {
            for error in errors {
                let error = error.with_source_code(source_text.clone());
                println!("{error:?}");
            }
        }
    }

    Ok(())
}

pub struct TransformOptions {
    //
    // Primary Options
    //
    /// The working directory that all paths in the programmatic options will be resolved relative to.
    pub cwd: PathBuf,

    // Core
    /// Set assumptions in order to produce smaller output.
    /// For more information, check the [assumptions](https://babel.dev/docs/assumptions) documentation page.
    pub assumptions: CompilerAssumptions,

    // Plugins
    /// [preset-typescript](https://babeljs.io/docs/babel-preset-typescript)
    pub typescript: TypeScriptOptions,

    /// Decorator
    pub decorator: DecoratorOptions,

    /// Jsx Transform
    ///
    /// See [preset-react](https://babeljs.io/docs/babel-preset-react)
    pub jsx: JsxOptions,

    /// ECMAScript Env Options
    pub env: EnvOptions,

    /// Proposals
    pub proposals: ProposalOptions,

    /// Plugins
    pub plugins: PluginsOptions,

    /// Helper loading configuration for generated runtime helpers.
    pub helper_loader: HelperLoaderOptions,
}

