fn run_transform_then_compress(
    source_text: &str,
    source_type: SourceType,
    transform_options: &TransformOptions,
    options: Option<CompressOptions>,
) -> String {
    let allocator = Allocator::default();
    let ret = Parser::new(&allocator, source_text, source_type)
        .with_options(ParseOptions { allow_return_outside_function: true, ..Default::default() })
        .parse();
    assert!(!ret.panicked, "{source_text}");
    assert!(ret.errors.is_empty(), "{source_text}");
    let mut program = ret.program;
    let scoping = SemanticBuilder::new().build(&program).semantic.into_scoping();
    let ret = Transformer::new(&allocator, Path::new("test.ts"), transform_options)
        .build_with_scoping(scoping, &mut program);
    assert!(ret.errors.is_empty(), "{source_text}");
    if let Some(options) = options {
        Compressor::new(&allocator).build_with_scoping(&mut program, ret.scoping, options);
    }
    Codegen::new()
        .with_options(CodegenOptions { single_quote: true, ..Default::default() })
        .build(&program)
        .code
}

